import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import {
  UsersIcon,
  ShieldCheckIcon,
  ExclamationTriangleIcon,
  CurrencyDollarIcon,
  ChartBarIcon,
  PlayIcon,
  StopIcon,
} from '@heroicons/react/24/outline';
import { useAuth } from '../../contexts/AuthContext';
import { adminAPI, claimAPI, simulationAPI } from '../../services/api';
import toast from 'react-hot-toast';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalWorkers: 0,
    activeWorkers: 0,
    totalPolicies: 0,
    activePolicies: 0,
    totalClaims: 0,
    pendingClaims: 0,
    approvedClaims: 0,
    rejectedClaims: 0,
    totalPayoutAmount: 0,
  });
  const [fraudStats, setFraudStats] = useState({
    totalClaims: 0,
    fraudClaims: 0,
    fraudRate: '0',
    manualReviewRate: '0',
  });
  const [payoutStats, setPayoutStats] = useState({
    totalPayouts: 0,
    successRate: '0',
    totalAmount: 0,
    averageAmount: 0,
  });
  const [loading, setLoading] = useState(true);
  const [simulationRunning, setSimulationRunning] = useState(false);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch dashboard stats
      const dashboardResponse = await adminAPI.getDashboardStats();
      setStats(dashboardResponse.data.data);

      // Fetch fraud statistics
      const fraudResponse = await claimAPI.getFraudStatistics('30d');
      setFraudStats(fraudResponse.data.data);

      // Fetch payout statistics
      const payoutResponse = await claimAPI.getPayoutStatistics('30d');
      setPayoutStats(payoutResponse.data.data);

    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const runSimulation = async () => {
    try {
      setSimulationRunning(true);

      // Get first active worker for simulation
      const workersRes = await adminAPI.getAllWorkers({ status: 'active', limit: 1 });
      const workers = workersRes.data.data || [];

      if (workers.length === 0) {
        toast.error('No active workers available for simulation');
        setSimulationRunning(false);
        return;
      }

      const simulationData = {
        scenarioId: 'heavy_rain',
        workerId: workers[0]._id
      };

      await simulationAPI.runSimulation(simulationData);
      toast.success('Simulation completed successfully');
      fetchDashboardData(); // Refresh data

    } catch (error) {
      console.error('Simulation error:', error);
      toast.error('Failed to run simulation');
    } finally {
      setSimulationRunning(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-purple-600 to-purple-700 rounded-lg p-6 text-white">
        <h1 className="text-2xl font-bold">
          Admin Dashboard
        </h1>
        <p className="mt-2 text-purple-100">
          Manage GigShield operations and monitor system performance.
        </p>
      </div>

      {/* Main Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <AdminStatCard
          title="Total Workers"
          value={stats.totalWorkers.toLocaleString()}
          subtitle={`${stats.activeWorkers} active`}
          icon={UsersIcon}
          color="blue"
        />
        <AdminStatCard
          title="Active Policies"
          value={stats.activePolicies.toLocaleString()}
          subtitle={`${stats.totalPolicies} total`}
          icon={ShieldCheckIcon}
          color="green"
        />
        <AdminStatCard
          title="Total Claims"
          value={stats.totalClaims.toLocaleString()}
          subtitle={`${stats.pendingClaims} pending`}
          icon={ExclamationTriangleIcon}
          color="yellow"
        />
        <AdminStatCard
          title="Total Payout"
          value={`₹${stats.totalPayoutAmount.toLocaleString()}`}
          subtitle={`${stats.approvedClaims} approved`}
          icon={CurrencyDollarIcon}
          color="purple"
        />
      </div>

      {/* Fraud and Payout Stats */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white rounded-lg shadow p-6">
          <h3 className="text-lg font-medium text-gray-900 mb-4">Fraud Detection</h3>
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Fraud Rate</span>
              <span className={`text-lg font-semibold ${
                parseFloat(fraudStats.fraudRate) > 5 ? 'text-red-600' : 'text-green-600'
              }`}>
                {fraudStats.fraudRate}%
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Manual Review Rate</span>
              <span className="text-lg font-semibold text-yellow-600">
                {fraudStats.manualReviewRate}%
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Total Fraud Claims</span>
              <span className="text-lg font-semibold text-red-600">
                {fraudStats.fraudClaims}
              </span>
            </div>
            <div className="pt-4 border-t">
              <Link
                to="/admin/claims"
                className="inline-flex items-center text-sm text-primary-600 hover:text-primary-500"
              >
                Review Claims →
              </Link>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <h3 className="text-lg font-medium text-gray-900 mb-4">Payout Performance</h3>
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Success Rate</span>
              <span className={`text-lg font-semibold ${
                parseFloat(payoutStats.successRate) > 95 ? 'text-green-600' : 'text-yellow-600'
              }`}>
                {payoutStats.successRate}%
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Total Processed</span>
              <span className="text-lg font-semibold text-blue-600">
                {payoutStats.totalPayouts}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Average Amount</span>
              <span className="text-lg font-semibold text-purple-600">
                ₹{payoutStats.averageAmount}
              </span>
            </div>
            <div className="pt-4 border-t">
              <Link
                to="/admin/claims"
                className="inline-flex items-center text-sm text-primary-600 hover:text-primary-500"
              >
                View Payouts →
              </Link>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="bg-white rounded-lg shadow p-6">
        <h3 className="text-lg font-medium text-gray-900 mb-4">Quick Actions</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <QuickActionButton
            title="Run Simulation"
            description="Test system with sample data"
            icon={PlayIcon}
            onClick={runSimulation}
            disabled={simulationRunning}
            color="green"
          />
          <QuickActionButton
            title="Manage Workers"
            description="View and manage worker accounts"
            icon={UsersIcon}
            link="/admin/workers"
            color="blue"
          />
          <QuickActionButton
            title="Review Claims"
            description="Process pending claims"
            icon={ExclamationTriangleIcon}
            link="/admin/claims"
            color="yellow"
          />
          <QuickActionButton
            title="View Analytics"
            description="Detailed system analytics"
            icon={ChartBarIcon}
            link="/admin/simulation"
            color="purple"
          />
        </div>
      </div>

      {/* Recent Activity */}
      <div className="bg-white rounded-lg shadow">
        <div className="px-6 py-4 border-b border-gray-200">
          <h3 className="text-lg font-medium text-gray-900">System Overview</h3>
        </div>
        <div className="p-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="text-center">
              <div className="text-2xl font-bold text-blue-600">
                {((stats.activeWorkers / stats.totalWorkers) * 100).toFixed(1)}%
              </div>
              <div className="text-sm text-gray-600 mt-1">Worker Activation Rate</div>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-green-600">
                {stats.totalPolicies > 0 ? ((stats.activePolicies / stats.totalPolicies) * 100).toFixed(1) : 0}%
              </div>
              <div className="text-sm text-gray-600 mt-1">Policy Renewal Rate</div>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-purple-600">
                {stats.totalClaims > 0 ? ((stats.approvedClaims / stats.totalClaims) * 100).toFixed(1) : 0}%
              </div>
              <div className="text-sm text-gray-600 mt-1">Claim Approval Rate</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const AdminStatCard = ({ title, value, subtitle, icon: Icon, color }) => {
  const colorClasses = {
    blue: 'bg-blue-500',
    green: 'bg-green-500',
    yellow: 'bg-yellow-500',
    purple: 'bg-purple-500',
  };

  const bgColorClasses = {
    blue: 'bg-blue-100',
    green: 'bg-green-100',
    yellow: 'bg-yellow-100',
    purple: 'bg-purple-100',
  };

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="flex items-center">
        <div className={`p-3 rounded-lg ${bgColorClasses[color]}`}>
          <Icon className={`h-6 w-6 ${colorClasses[color]} text-white`} />
        </div>
        <div className="ml-4 flex-1">
          <p className="text-sm font-medium text-gray-600">{title}</p>
          <p className="text-2xl font-semibold text-gray-900">{value}</p>
          <p className="text-sm text-gray-500">{subtitle}</p>
        </div>
      </div>
    </div>
  );
};

const QuickActionButton = ({ title, description, icon: Icon, onClick, link, disabled, color }) => {
  const colorClasses = {
    blue: 'text-blue-600 hover:bg-blue-50 border-blue-200',
    green: 'text-green-600 hover:bg-green-50 border-green-200',
    yellow: 'text-yellow-600 hover:bg-yellow-50 border-yellow-200',
    purple: 'text-purple-600 hover:bg-purple-50 border-purple-200',
  };

  const bgColorClasses = {
    blue: 'bg-blue-100',
    green: 'bg-green-100',
    yellow: 'bg-yellow-100',
    purple: 'bg-purple-100',
  };

  const Component = link ? Link : 'button';
  const props = link ? { to: link } : { onClick, disabled };

  return (
    <Component
      {...props}
      className={`p-4 rounded-lg border-2 transition-colors ${
        disabled ? 'opacity-50 cursor-not-allowed' : colorClasses[color]
      } ${!link ? bgColorClasses[color] : ''}`}
    >
      <Icon className="h-6 w-6 mb-2" />
      <h4 className="font-medium text-gray-900">{title}</h4>
      <p className="text-sm text-gray-600 mt-1">{description}</p>
    </Component>
  );
};

export default AdminDashboard;
